            'views' => 1923,
        ]);

        News::create([
            'title' => 'Árvore Geradora Mínima',
            'content_json' => '{"type":"doc","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Dado um grafo conexo ponderado G, uma árvore geradora mínima (MST) de G é uma árvore geradora de peso mínimo"}]},{"type":"paragraph","attrs":{"textAlign":null}},{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","marks":[{"type":"bold"}],"text":"Algoritmo de Prim"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"O algoritmo de Prim é um algoritmo guloso que constrói a MST crescendo a partir de um vértice raiz, adicionalmente a cada passo a aresta de menor peso que conecta a árvore já construída a um vértice ainda não incluído"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"1- Inicie a árvore a partir de um vértice qualquer"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"2- Faça a árvore crescer com uma aresta. Dentre as arestas conectam a árvore a vértices que ainda não fazem parte da árvore. Escolhendo a de menor custo"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"3- Repete o passo anterior até que todos os vértices sejam conectados à árvore"}]},{"type":"paragraph","attrs":{"textAlign":null}},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Na versão simples, são mantidos dois vetores:"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"chave[v] - menor peso de aresta conhecida ligada v à árvore"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"pred[v] - predecessor de v na MST"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"inMST[v] - se v já foi incluído"}]},{"type":"codeBlock","attrs":{"language":"jsx"},"content":[{"type":"text","text":"Prim-Ingenuo(G,w,r):\\n\\tpara cada u pertencente a V faça:\\n\\t\\tchave[u] = infinito\\n\\t\\tpred[u] = nulo\\n\\t\\tinMST[u] = falso\\n\\tchave[r] = 0\\n\\trepita:\\n\\t\\tu = vertice que não está na MST com menor chave\\n\\t\\tinMST[v] = verdadeiro\\n\\t\\tpara cada v pertencente Adj[u] faça:\\n\\t\\t\\tse não(inMST[v]) e w(u,v) < chave[v] então:\\n\\t\\t\\t\\tpred[v] = u\\n\\t\\t\\t\\tchave[v] = w(u,v)\\n"}]},{"type":"paragraph","attrs":{"textAlign":null}},{"type":"codeBlock","attrs":{"language":"jsx"},"content":[{"type":"text","text":"int menorChave(int chave[], bool inMST[]){\\n\\tint min = INT_MAX, min_index\\n\\tfor(int v =0; v<V; v++)\\n\\t\\tif(inMST[v]==false && chave[v]<min)\\n\\t\\t\\tmin = chave[v], min_index = v;\\n\\treturn min_index;\\n}\\n\\nvoid primMST(int adj[V][V]){\\n\\tint pred[V], chave[V];\\n\\tbool inMST[V];\\n\\tfor(int i =0;i<V; i++)\\n\\t\\tchave[i] = INT_MAX, inMST[i] = false\\n\\tchave[0]=0; pred[0] = -1;\\n\\tfor(int count = 0; count<V-1; count++){\\n\\t\\tint u = menorChave(chave, inMST);\\n\\t\\tinMST[u] = true;\\n\\t\\tfor (int v = 0; v<V; v++)\\n\\t\\t\\tif(adj[u][v] && inMST[v] == false && adj[u][v]<chave[v])\\n\\t\\t\\t\\tpred[v] = u, chave[v] = adj[u][]\\n\\t}\\n\\tprintMST(pred, adj\\n\\t\\n"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"bold"}],"text":"Gargalo da versão ingênua:"},{"type":"text","text":" A busca pelo vértice com menor key é O(V) por iteração. Para grafos esparsos, podemos fazer muito melhor usando uma min-heap"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Um "},{"type":"text","marks":[{"type":"bold"}],"text":"Heap Binário Mínimo"},{"type":"text","text":" permite entre outros:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Push(chave, valor): inserir na fila de prioridade em O(log n)"}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"ExtractMin(): remover o mínimo em O(log n) e o retorna"}]}]}]},{"type":"paragraph","attrs":{"textAlign":null}},{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"Disjoint Set Union (DSU)"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Em um jogo, n amigos inicialmente jogam individualmente. Alianças são formadas gradualmente. A relação de aliança é transitiva: se A e B são aliados e B e C são aliados, então A e C também são"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Operação 1: Unir dois grupos (join)"},{"type":"hardBreak"},{"type":"text","text":"Operação2: Verificar se dois amigos estão no mesmo grupo (find)"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Solução ingênua:"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Construir um grafo e usar BFS/DFS para cada consulta"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Join: O(1) inserir arestas"}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Find: O(V+E)"}]}]}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Nesse caso consultas são lentas"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Em um DSU, cada componente conexo é representado como uma árvore. A raiz é o representante do componente Implementado como um array pai[]: pai[i] = pai de i ou i se i for a raiz"}]},{"type":"paragraph","attrs":{"textAlign":null}},{"type":"image","attrs":{"src":"attachment:3b0cabac-0ab9-45a8-8573-3600010689aa:image.png","alt":"image.png","title":null,"width":"100%","height":null,"align":"center"}},{"type":"codeBlock","attrs":{"language":"jsx"},"content":[{"type":"text","text":"int *pai;\\nvoid init(ll N){\\n\\tpai = malloc(sizeof(int)*(N+1));\\n\\tfor (int i=0; i<=N; i++) pai[i]=i\\n}\\n\\nll find(ll x){\\n\\tif(x==pai[x]) return x;\\n\\telse return find(pai[x]);\\n}\\n\\nvoid join(ll a, llb){\\n\\tpai[find(a)] = find(b)\\n}\\n"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"O pior caso sem otimização é se sempre unirmos o menor ao maior sem critério, a árvore poderia ficar degenerada, ou seja, uma lista encadeada. Nesse caso, o find custa O(n)"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"bold"}],"text":"Path Compression:"},{"type":"text","text":" Ao executar um find(x), salvamos diretamente o representante em pai[x] chamadas"}]},{"type":"codeBlock","attrs":{"language":"jsx"},"content":[{"type":"text","text":"ll find(ll x){\\n\\tif(x==pai[x])\\n\\t\\treturn x;\\n\\telse\\n\\t\\treturn pai[x] = find(pai[x]);\\n}\\n"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"bold"}],"text":"Union by Size:"},{"type":"text","text":" Ao unir dois conjuntos, sempre anexe o menor ao maior, isso garante que a altura da árvore nunca exceda O(log n)"}]},{"type":"codeBlock","attrs":{"language":"jsx"},"content":[{"type":"text","text":"int *pai, *tamanho\\n\\nvoid init(ll n){\\n\\tpai = malloc(sizeof(int)*(N+1))\\n\\ttamanho =  malloc(sizeof(int)*(N+1))\\n\\tfor(int i=0; i<=N; i++){\\n\\t\\tpai[i] = i; tamanho[i] = 1;\\n\\t}\\n}\\n\\nvoid join(ll a, ll b){\\n\\ta = find(a)\\n\\tb = find(b)\\n\\tif(a!=b){\\n\\t\\tif(tamanho[a] < tamanho[b])\\n\\t\\t\\tswap(a,b);\\n\\t\\tpai[b] = a;\\n\\t\\ttamanho[a]+=tamanho[b]\\n\\t}\\n}\\n"}]},{"type":"paragraph","attrs":{"textAlign":null}},{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"Algoritmo de Kruskal"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"DecreaseKey(): alterar o valor da chave e o reposiciona em O(log n)"}]}]}]},{"type":"codeBlock","attrs":{"language":"jsx"},"content":[{"type":"text","text":"Prim-Heap(G,w,r):\\n\\tpara cada u pertencente a V:\\n\\t\\tchave[u] = infinito\\n\\t\\tpred[u] = NULL\\n\\t\\tinMST[u] = false\\n\\tchave[r]=0\\n\\tQ = min-heap com todos os vértices priorizados por chave[]\\n\\tequanto Q não for vazio:\\n\\t\\tu = ExtractMin(Q)\\n\\t\\tinMST[u] = verdadeiro\\n\\t\\tpara cada v pertencente Adj[u] com peso w(u,v) faça:\\n\\t\\t\\tse (inMST[v] == false) e w(u,v)<chave[v] então:\\n\\t\\t\\t\\tpred[v] = u\\n\\t\\t\\t\\tchave[v] =w(u,v)\\n\\t\\t\\t\\tDecreaseKey(Q, v, chave[v]S)\\n"}]},{"type":"paragraph","attrs":{"textAlign":null}}]}',
            'content_html' => '<p>Dado um grafo conexo ponderado G, uma árvore geradora mínima (MST) de G é uma árvore geradora de peso mínimo</p><p></p><h2 class="text-3xl font-semibold mt-6 mb-3 text-gray-900 font-title"><strong>Algoritmo de Prim</strong></h2><p>O algoritmo de Prim é um algoritmo guloso que constrói a MST crescendo a partir de um vértice raiz, adicionalmente a cada passo a aresta de menor peso que conecta a árvore já construída a um vértice ainda não incluído</p><p>1- Inicie a árvore a partir de um vértice qualquer</p><p>2- Faça a árvore crescer com uma aresta. Dentre as arestas conectam a árvore a vértices que ainda não fazem parte da árvore. Escolhendo a de menor custo</p><p>3- Repete o passo anterior até que todos os vértices sejam conectados à árvore</p><p></p><p>Na versão simples, são mantidos dois vetores:</p><p>chave[v] - menor peso de aresta conhecida ligada v à árvore</p><p>pred[v] - predecessor de v na MST</p><p>inMST[v] - se v já foi incluído</p><pre><code class="language-jsx">Prim-Ingenuo(G,w,r):\r\n\tpara cada u pertencente a V faça:\r\n\t\tchave[u] = infinito\r\n\t\tpred[u] = nulo\r\n\t\tinMST[u] = falso\r\n\tchave[r] = 0\r\n\trepita:\r\n\t\tu = vertice que não está na MST com menor chave\r\n\t\tinMST[v] = verdadeiro\r\n\t\tpara cada v pertencente Adj[u] faça:\r\n\t\t\tse não(inMST[v]) e w(u,v) &lt; chave[v] então:\r\n\t\t\t\tpred[v] = u\r\n\t\t\t\tchave[v] = w(u,v)\r\n</code></pre><p></p><pre><code class="language-jsx">int menorChave(int chave[], bool inMST[]){\r\n\tint min = INT_MAX, min_index\r\n\tfor(int v =0; v&lt;V; v++)\r\n\t\tif(inMST[v]==false &amp;&amp; chave[v]&lt;min)\r\n\t\t\tmin = chave[v], min_index = v;\r\n\treturn min_index;\r\n}\r\n\r\nvoid primMST(int adj[V][V]){\r\n\tint pred[V], chave[V];\r\n\tbool inMST[V];\r\n\tfor(int i =0;i&lt;V; i++)\r\n\t\tchave[i] = INT_MAX, inMST[i] = false\r\n\tchave[0]=0; pred[0] = -1;\r\n\tfor(int count = 0; count&lt;V-1; count++){\r\n\t\tint u = menorChave(chave, inMST);\r\n\t\tinMST[u] = true;\r\n\t\tfor (int v = 0; v&lt;V; v++)\r\n\t\t\tif(adj[u][v] &amp;&amp; inMST[v] == false &amp;&amp; adj[u][v]&lt;chave[v])\r\n\t\t\t\tpred[v] = u, chave[v] = adj[u][]\r\n\t}\r\n\tprintMST(pred, adj\r\n\t\r\n</code></pre><p><strong>Gargalo da versão ingênua:</strong> A busca pelo vértice com menor key é O(V) por iteração. Para grafos esparsos, podemos fazer muito melhor usando uma min-heap</p><p>Um <strong>Heap Binário Mínimo</strong> permite entre outros:</p><ul><li><p>Push(chave, valor): inserir na fila de prioridade em O(log n)</p></li><li><p>ExtractMin(): remover o mínimo em O(log n) e o retorna</p></li></ul><p></p><h2 class="text-3xl font-semibold mt-6 mb-3 text-gray-900 font-title">Disjoint Set Union (DSU)</h2><p>Em um jogo, n amigos inicialmente jogam individualmente. Alianças são formadas gradualmente. A relação de aliança é transitiva: se A e B são aliados e B e C são aliados, então A e C também são</p><p>Operação 1: Unir dois grupos (join)<br>Operação2: Verificar se dois amigos estão no mesmo grupo (find)</p><p>Solução ingênua:</p><p>Construir um grafo e usar BFS/DFS para cada consulta</p><ul><li><p>Join: O(1) inserir arestas</p></li><li><p>Find: O(V+E)</p></li></ul><p>Nesse caso consultas são lentas</p><p>Em um DSU, cada componente conexo é representado como uma árvore. A raiz é o representante do componente Implementado como um array pai[]: pai[i] = pai de i ou i se i for a raiz</p><p></p><img src="attachment:3b0cabac-0ab9-45a8-8573-3600010689aa:image.png" alt="image.png" width="100%" data-align="center" style="display: block; margin: 1rem auto; clear: both;"><pre><code class="language-jsx">int *pai;\r\nvoid init(ll N){\r\n\tpai = malloc(sizeof(int)*(N+1));\r\n\tfor (int i=0; i&lt;=N; i++) pai[i]=i\r\n}\r\n\r\nll find(ll x){\r\n\tif(x==pai[x]) return x;\r\n\telse return find(pai[x]);\r\n}\r\n\r\nvoid join(ll a, llb){\r\n\tpai[find(a)] = find(b)\r\n}\r\n</code></pre><p>O pior caso sem otimização é se sempre unirmos o menor ao maior sem critério, a árvore poderia ficar degenerada, ou seja, uma lista encadeada. Nesse caso, o find custa O(n)</p><p><strong>Path Compression:</strong> Ao executar um find(x), salvamos diretamente o representante em pai[x] chamadas</p><pre><code class="language-jsx">ll find(ll x){\r\n\tif(x==pai[x])\r\n\t\treturn x;\r\n\telse\r\n\t\treturn pai[x] = find(pai[x]);\r\n}\r\n</code></pre><p><strong>Union by Size:</strong> Ao unir dois conjuntos, sempre anexe o menor ao maior, isso garante que a altura da árvore nunca exceda O(log n)</p><pre><code class="language-jsx">int *pai, *tamanho\r\n\r\nvoid init(ll n){\r\n\tpai = malloc(sizeof(int)*(N+1))\r\n\ttamanho =  malloc(sizeof(int)*(N+1))\r\n\tfor(int i=0; i&lt;=N; i++){\r\n\t\tpai[i] = i; tamanho[i] = 1;\r\n\t}\r\n}\r\n\r\nvoid join(ll a, ll b){\r\n\ta = find(a)\r\n\tb = find(b)\r\n\tif(a!=b){\r\n\t\tif(tamanho[a] &lt; tamanho[b])\r\n\t\t\tswap(a,b);\r\n\t\tpai[b] = a;\r\n\t\ttamanho[a]+=tamanho[b]\r\n\t}\r\n}\r\n</code></pre><p></p><h2 class="text-3xl font-semibold mt-6 mb-3 text-gray-900 font-title">Algoritmo de Kruskal</h2><ul><li><p>DecreaseKey(): alterar o valor da chave e o reposiciona em O(log n)</p></li></ul><pre><code class="language-jsx">Prim-Heap(G,w,r):\r\n\tpara cada u pertencente a V:\r\n\t\tchave[u] = infinito\r\n\t\tpred[u] = NULL\r\n\t\tinMST[u] = false\r\n\tchave[r]=0\r\n\tQ = min-heap com todos os vértices priorizados por chave[]\r\n\tequanto Q não for vazio:\r\n\t\tu = ExtractMin(Q)\r\n\t\tinMST[u] = verdadeiro\r\n\t\tpara cada v pertencente Adj[u] com peso w(u,v) faça:\r\n\t\t\tse (inMST[v] == false) e w(u,v)&lt;chave[v] então:\r\n\t\t\t\tpred[v] = u\r\n\t\t\t\tchave[v] =w(u,v)\r\n\t\t\t\tDecreaseKey(Q, v, chave[v]S)\r\n</code></pre><p></p>',
